('stress_assessment', 'Evaluación de Estrés y Salud Mental', 'Diagnóstico de estrés y capacidad de manejo emocional', 'domain_specific', 6, ARRAY['stress','sleep','hormonal','cognitive'], 2, '[{"question_id":1,"question_text":"¿Cuál es tu nivel de estrés general actualmente?","question_type":"single_select","options":[{"text":"Extremo, siento que no puedo más","scores":{"stress":10,"hormonal":10,"sleep":15,"cognitive":15}},{"text":"Alto, estoy frecuentemente estresado","scores":{"stress":30,"hormonal":30,"sleep":35,"cognitive":35}},{"text":"Moderado, manejable pero presente","scores":{"stress":55,"hormonal":55,"sleep":55,"cognitive":55}},{"text":"Bajo, me siento en control","scores":{"stress":90,"hormonal":85,"sleep":85,"cognitive":85}}]},{"question_id":2,"question_text":"¿Con qué frecuencia sientes ansiedad?","question_type":"single_select","options":[{"text":"Constante, prácticamente todo el día","scores":{"stress":10,"cognitive":10,"sleep":10,"hormonal":15}},{"text":"Varias veces al día","scores":{"stress":30,"cognitive":30,"sleep":30,"hormonal":35}},{"text":"Ocasionalmente, en momentos puntuales","scores":{"stress":60,"cognitive":60,"sleep":60,"hormonal":60}},{"text":"Rara vez o nunca","scores":{"stress":90,"cognitive":90,"sleep":85,"hormonal":85}}]},{"question_id":3,"question_text":"¿Cómo manejas los conflictos o situaciones difíciles?","question_type":"single_select","options":[{"text":"Me desbordo, reacciono con ira o llanto","scores":{"stress":10,"cognitive":15,"hormonal":15}},{"text":"Me cuesta mucho, me afectan por días","scores":{"stress":30,"cognitive":35,"hormonal":35}},{"text":"Los manejo pero me generan tensión","scores":{"stress":55,"cognitive":55,"hormonal":55}},{"text":"Los enfrento con calma y claridad","scores":{"stress":90,"cognitive":85,"hormonal":85}}]},{"question_id":4,"question_text":"¿Practicas alguna técnica de manejo de estrés?","question_type":"single_select","options":[{"text":"No, ni sé cuáles existen","scores":{"stress":10,"cognitive":15,"sleep":15}},{"text":"Lo he intentado pero no soy consistente","scores":{"stress":35,"cognitive":40,"sleep":40}},{"text":"Sí, meditación o respiración de vez en cuando","scores":{"stress":65,"cognitive":65,"sleep":65}},{"text":"Sí, tengo una práctica diaria establecida","scores":{"stress":90,"cognitive":85,"sleep":85}}]},{"question_id":5,"question_text":"¿Cómo afecta el estrés a tu sueño?","question_type":"single_select","options":[{"text":"No puedo dormir, pensamientos acelerados","scores":{"sleep":10,"stress":10,"hormonal":15,"cognitive":15}},{"text":"Me cuesta dormir y me despierto en la noche","scores":{"sleep":30,"stress":30,"hormonal":35,"cognitive":35}},{"text":"A veces me afecta, pero no siempre","scores":{"sleep":55,"stress":55,"hormonal":55,"cognitive":55}},{"text":"Duermo bien independientemente del estrés","scores":{"sleep":90,"stress":85,"hormonal":85,"cognitive":85}}]},{"question_id":6,"question_text":"¿Experimentas síntomas físicos de estrés?","question_type":"single_select","options":[{"text":"Sí, dolor de cabeza, tensión muscular, problemas digestivos frecuentes","scores":{"stress":10,"hormonal":10,"sleep":15,"cognitive":15}},{"text":"Tensión muscular y dolores de cabeza frecuentes","scores":{"stress":30,"hormonal":30,"sleep":35,"cognitive":35}},{"text":"Ocasionalmente tensión en cuello/hombros","scores":{"stress":60,"hormonal":60,"sleep":60,"cognitive":60}},{"text":"No, mi cuerpo maneja bien el estrés","scores":{"stress":90,"hormonal":85,"sleep":85,"cognitive":85}}]},{"question_id":7,"question_text":"¿Cómo está tu capacidad de concentración?","question_type":"single_select","options":[{"text":"No puedo concentrarme, mente dispersa","scores":{"cognitive":10,"stress":15,"sleep":15,"hormonal":15}},{"text":"Me cuesta mucho enfocarme","scores":{"cognitive":30,"stress":35,"sleep":35,"hormonal":35}},{"text":"Puedo concentrarme con esfuerzo","scores":{"cognitive":60,"stress":60,"sleep":60,"hormonal":55}},{"text":"Excelente enfoque y claridad mental","scores":{"cognitive":90,"stress":85,"sleep":85,"hormonal":85}}]},{"question_id":8,"question_text":"¿Cuánto tiempo dedicas a actividades que disfrutas?","question_type":"single_select","options":[{"text":"Nada, no tengo tiempo ni energía","scores":{"stress":10,"cognitive":15,"hormonal":15}},{"text":"Muy poco, casi todo es obligaciones","scores":{"stress":30,"cognitive":40,"hormonal":35}},{"text":"Algo, intento hacer espacio","scores":{"stress":60,"cognitive":60,"hormonal":60}},{"text":"Regularmente, es parte de mi rutina","scores":{"stress":90,"cognitive":85,"hormonal":85}}]},{"question_id":9,"question_text":"¿Sientes que tienes un propósito claro en la vida?","question_type":"single_select","options":[{"text":"No, me siento perdido y sin dirección","scores":{"stress":10,"cognitive":10,"hormonal":15}},{"text":"No estoy seguro, estoy buscando","scores":{"stress":35,"cognitive":35,"hormonal":40}},{"text":"Tengo una idea pero no es muy clara","scores":{"stress":60,"cognitive":60,"hormonal":60}},{"text":"Sí, sé exactamente hacia dónde voy","scores":{"stress":90,"cognitive":90,"hormonal":85}}]}]'::jsonb, '[{"condition":"stress < 40","protocol_id":"protocolo_antiestres","priority":1},{"condition":"cognitive < 40","protocol_id":"protocolo_cognitivo_focus","priority":2}]'::jsonb, true, 'standard'),

-- ═══ Quiz 5: Evaluación de Digestión ═══
('digestion_assessment', 'Evaluación de Digestión', 'Diagnóstico del estado digestivo', 'domain_specific', 4, ARRAY['digestive','inflammation','metabolic'], 2, '[{"question_id":1,"question_text":"¿Cómo describirías tu digestión general?","question_type":"single_select","options":[{"text":"Muy mala, problemas diarios severos","scores":{"digestive":10,"inflammation":10,"metabolic":15}},{"text":"Mala, molestias frecuentes","scores":{"digestive":30,"inflammation":30,"metabolic":35}},{"text":"Aceptable, molestias ocasionales","scores":{"digestive":60,"inflammation":60,"metabolic":60}},{"text":"Excelente, sin ningún problema","scores":{"digestive":90,"inflammation":85,"metabolic":85}}]},{"question_id":2,"question_text":"¿Experimentas hinchazón abdominal?","question_type":"single_select","options":[{"text":"Sí, después de cada comida","scores":{"digestive":10,"inflammation":10,"metabolic":15}},{"text":"Frecuentemente, varias veces por semana","scores":{"digestive":30,"inflammation":30,"metabolic":35}},{"text":"Ocasionalmente, con ciertos alimentos","scores":{"digestive":55,"inflammation":55,"metabolic":55}},{"text":"Nunca o casi nunca","scores":{"digestive":90,"inflammation":85,"metabolic":85}}]},{"question_id":3,"question_text":"¿Cómo son tus evacuaciones intestinales?","question_type":"single_select","options":[{"text":"Muy irregulares, estreñimiento o diarrea frecuente","scores":{"digestive":10,"inflammation":15,"metabolic":15}},{"text":"Irregulares, cambian constantemente","scores":{"digestive":30,"inflammation":35,"metabolic":35}},{"text":"Bastante regulares con alguna variación","scores":{"digestive":60,"inflammation":60,"metabolic":60}},{"text":"Regulares, 1-2 veces al día, consistencia normal","scores":{"digestive":95,"inflammation":85,"metabolic":85}}]},{"question_id":4,"question_text":"¿Tienes sensibilidad a algún alimento?","question_type":"single_select","options":[{"text":"Sí, muchos alimentos me caen mal","scores":{"digestive":10,"inflammation":10,"metabolic":15}},{"text":"Algunos alimentos específicos me afectan","scores":{"digestive":35,"inflammation":35,"metabolic":40}},{"text":"Uno o dos que evito","scores":{"digestive":60,"inflammation":60,"metabolic":60}},{"text":"No, tolero todo bien","scores":{"digestive":90,"inflammation":85,"metabolic":85}}]},{"question_id":5,"question_text":"¿Experimentas reflujo o acidez?","question_type":"single_select","options":[{"text":"Sí, casi a diario","scores":{"digestive":10,"inflammation":15,"metabolic":15}},{"text":"Varias veces por semana","scores":{"digestive":30,"inflammation":35,"metabolic":35}},{"text":"Ocasionalmente","scores":{"digestive":60,"inflammation":60,"metabolic":60}},{"text":"Nunca","scores":{"digestive":90,"inflammation":90,"metabolic":85}}]},{"question_id":6,"question_text":"¿Te han diagnosticado alguna condición digestiva?","question_type":"multi_select","options":[{"text":"Síndrome de intestino irritable (SII)","scores":{"digestive":-20,"inflammation":-15,"metabolic":-10}},{"text":"Gastritis o úlceras","scores":{"digestive":-20,"inflammation":-15,"metabolic":-10}},{"text":"Enfermedad celíaca o sensibilidad al gluten","scores":{"digestive":-25,"inflammation":-20,"metabolic":-15}},{"text":"Ninguna condición diagnosticada","scores":{"digestive":20,"inflammation":15,"metabolic":10}}]},{"question_id":7,"question_text":"¿Cuánta fibra y alimentos fermentados consumes?","question_type":"single_select","options":[{"text":"Casi nada de fibra ni fermentados","scores":{"digestive":10,"inflammation":15,"metabolic":15}},{"text":"Poca fibra, sin fermentados","scores":{"digestive":35,"inflammation":40,"metabolic":35}},{"text":"Fibra moderada, algo de fermentados","scores":{"digestive":65,"inflammation":65,"metabolic":65}},{"text":"Alto en fibra y fermentados diariamente","scores":{"digestive":90,"inflammation":85,"metabolic":85}}]}]'::jsonb, '[{"condition":"digestive < 40","protocol_id":"protocolo_digestivo","priority":1},{"condition":"inflammation < 50 AND digestive < 60","protocol_id":"protocolo_antiinflamatorio","priority":2}]'::jsonb, true, 'standard'),

-- ═══ Quiz 6: Evaluación de Dolor y Movilidad ═══
('pain_mobility_assessment', 'Evaluación de Dolor y Movilidad', 'Diagnóstico de dolor y limitaciones de movimiento', 'domain_specific', 5, ARRAY['pain','inflammation','fitness'], 2, '[{"question_id":1,"question_text":"¿Experimentas dolor crónico en alguna parte del cuerpo?","question_type":"single_select","options":[{"text":"Sí, dolor constante que limita mi vida diaria","scores":{"pain":10,"inflammation":10,"fitness":10}},{"text":"Sí, dolor frecuente que me molesta","scores":{"pain":30,"inflammation":30,"fitness":30}},{"text":"Dolor ocasional con ciertos movimientos","scores":{"pain":55,"inflammation":55,"fitness":55}},{"text":"No, estoy libre de dolor","scores":{"pain":95,"inflammation":85,"fitness":85}}]},{"question_id":2,"question_text":"¿En qué zonas sientes dolor o molestia?","question_type":"multi_select","options":[{"text":"Espalda baja (lumbar)","scores":{"pain":-15,"inflammation":-10,"fitness":-10}},{"text":"Cuello y hombros","scores":{"pain":-10,"inflammation":-10,"fitness":-5}},{"text":"Rodillas","scores":{"pain":-15,"inflammation":-10,"fitness":-15}},{"text":"Caderas","scores":{"pain":-10,"inflammation":-10,"fitness":-10}},{"text":"Sin dolor en ninguna zona","scores":{"pain":20,"inflammation":15,"fitness":15}}]},{"question_id":3,"question_text":"¿Cómo es tu movilidad general?","question_type":"single_select","options":[{"text":"Muy limitada, me cuesta agacharme y moverme","scores":{"pain":10,"fitness":10,"inflammation":15}},{"text":"Limitada, siento rigidez frecuente","scores":{"pain":30,"fitness":30,"inflammation":35}},{"text":"Aceptable, algo rígido en las mañanas","scores":{"pain":55,"fitness":55,"inflammation":55}},{"text":"Excelente, me muevo sin restricciones","scores":{"pain":90,"fitness":90,"inflammation":85}}]},{"question_id":4,"question_text":"¿El dolor limita tu capacidad de hacer ejercicio?","question_type":"single_select","options":[{"text":"Sí, no puedo hacer ejercicio por el dolor","scores":{"pain":10,"fitness":10,"inflammation":10}},{"text":"Sí, tengo que modificar muchos ejercicios","scores":{"pain":30,"fitness":30,"inflammation":30}},{"text":"Algo, evito ciertos movimientos","scores":{"pain":55,"fitness":55,"inflammation":55}},{"text":"No, puedo entrenar sin limitaciones","scores":{"pain":90,"fitness":90,"inflammation":85}}]},{"question_id":5,"question_text":"¿Haces trabajo de movilidad o estiramientos?","question_type":"single_select","options":[{"text":"Nunca","scores":{"pain":15,"fitness":10,"inflammation":15}},{"text":"Rara vez, cuando me acuerdo","scores":{"pain":35,"fitness":30,"inflammation":35}},{"text":"2-3 veces por semana","scores":{"pain":65,"fitness":65,"inflammation":65}},{"text":"Diariamente, es parte de mi rutina","scores":{"pain":90,"fitness":85,"inflammation":85}}]},{"question_id":6,"question_text":"¿Qué tratamientos has probado para el dolor?","question_type":"multi_select","options":[{"text":"Analgésicos frecuentemente","scores":{"pain":-15,"inflammation":-15,"fitness":-5}},{"text":"Fisioterapia","scores":{"pain":5,"inflammation":5,"fitness":5}},{"text":"Ejercicio correctivo","scores":{"pain":10,"inflammation":5,"fitness":10}},{"text":"Nada, no he necesitado tratamiento","scores":{"pain":15,"inflammation":10,"fitness":10}}]},{"question_id":7,"question_text":"¿Cuántas horas pasas sentado al día?","question_type":"single_select","options":[{"text":"Más de 10 horas","scores":{"pain":10,"fitness":10,"inflammation":15}},{"text":"8-10 horas","scores":{"pain":30,"fitness":30,"inflammation":35}},{"text":"4-8 horas con pausas activas","scores":{"pain":60,"fitness":60,"inflammation":60}},{"text":"Menos de 4 horas, me muevo mucho","scores":{"pain":90,"fitness":85,"inflammation":85}}]}]'::jsonb, '[{"condition":"pain < 50","protocol_id":"protocolo_movilidad_dolor","priority":1},{"condition":"inflammation < 50 AND pain < 60","protocol_id":"protocolo_antiinflamatorio","priority":2}]'::jsonb, true, 'standard');
